#include <bits/stdc++.h>
using namespace std;

const int N=402;

int n,m,cnt[N],tmp[N];
bool flag=true;

int main(){
	scanf("%d%d",&n,&m);
	for(int i=1,x;i<=3*m+1;i++){
		scanf("%d",&x);
		cnt[x]++;
	}
	for(int i=1;i<=n;i++){
		for(int k=1;k<=n;k++){
			for(int j=1;j<=n;j++)
				tmp[j]=cnt[j];
			tmp[i]++;
			if(tmp[k]<2)
				continue;
			tmp[k]-=2;
			bool f=1;
			for(int j=1;j<=n && f;j++){
				tmp[j]%=3;
				if(tmp[j]){
					if(min(tmp[j+1],tmp[j+2])<tmp[j])
						f=0;
					else
						tmp[j+1]-=tmp[j],tmp[j+2]-=tmp[j],tmp[j]=0;
				}
			}
			if(f){
				flag=false;
				printf("%d ",i);
				break;
			}
		}
	}
	if(flag)
		printf("NO");
	return 0;
}
